const kb = $input.first().json;
const cd = kb.crawl_data || {};
const persona = cd.persona || {};
const brandVoice = kb.brand_voice || '';
const services = (kb.services || []).join(', ');
const specials = (cd.daily_specials || []).map(s => `${s.name} - ${s.description}`).join('\n');
const industry = cd.industry || 'business';

const prompt = `You are a content strategist for ${kb.company_name || 'the business'}.

Brand voice: ${brandVoice}
Industry: ${industry}
Services: ${services}
${specials ? 'Current specials:\n' + specials : ''}

Create 7 social media content pieces for this week. For each piece, provide:
1. Platform (Instagram, LinkedIn, or TikTok)
2. Content pillar (Educational, Behind-the-scenes, Social proof, Thought leadership, or Engagement)
3. Hook (first line to grab attention)
4. Full post text (platform-optimized length)
5. Suggested hashtags
6. Best posting time

Mix platforms and pillars across the week. Make content feel authentic, not corporate. Use the brand voice naturally.`;

return [{ json: { prompt, companyName: kb.company_name, clientId: kb.client_id } }];

const r = $input.first().json;
let content = r?.choices?.[0]?.message?.content || 'No content generated';
// Clean thinking tags if present
content = content.replace(/<think>[\s\S]*?<\/think>\s*/g, '').trim();

const prev = $node['Build Content Brief'].json;

// Log to Supabase
return [{ json: {
  content: content,
  companyName: prev.companyName,
  clientId: prev.clientId,
  generatedAt: new Date().toISOString(),
  model: 'qwen/qwen3.6-plus-preview:free',
  cost: 0
}}];
